476	function blendWithClusterPrior(
477	    baseScore: number,
478	    row: ActionScore,
479	    clusterPrior: ClusterPrior | undefined,
480	): number {
481	    if (!clusterPrior) return baseScore;
482	
483	    const sampleCount = Number(row.total_attempts ?? 0);
484	    if (sampleCount >= CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD) {
485	        return baseScore;
486	    }
487	
488	    const deficitWeight = (CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD - sampleCount)
489	        / CLUSTER_PRIOR_LOW_SAMPLE_THRESHOLD;
490	    const priorStrength = Math.min(
491	        1,
492	        clusterPrior.totalAttempts / CLUSTER_PRIOR_STRONG_SIGNAL_MIN_SAMPLES,
493	    );
494	    const blendWeight = Math.min(
495	        CLUSTER_PRIOR_MAX_BLEND,
496	        deficitWeight * priorStrength * CLUSTER_PRIOR_MAX_BLEND,
497	    );
498	
499	    const blended = (baseScore * (1 - blendWeight)) + (clusterPrior.successRate * blendWeight);
500	    return Math.max(0, Math.min(1, blended));
501	}
