195	        .replace(/^_+|_+$/g, '') || issueType.trim();
196	
197	    const normalizedEnv = (environment ?? 'production').trim().toLowerCase() || 'production';
198	
199	    try {
200	        // Exact match on (customer_id, issue_type, environment)
201	        const { data, error } = await supabase
202	            .from('dim_contexts')
203	            .select('context_id, issue_type, environment, customer_tier')
204	            .eq('customer_id', customerId)
205	            .eq('issue_type', normalizedIssueType)
206	            .eq('environment', normalizedEnv)
207	            .limit(1)
208	            .maybeSingle();
209	
210	        if (!error && data?.context_id) {
211	            return {
212	                resolved: true,
213	                contextId: data.context_id as string,
214	                label: `${normalizedIssueType} / ${normalizedEnv}${customerTier ? ` / ${customerTier}` : ''}`,
215	            };
216	        }
217	
218	        // Fallback: match just issue_type for this customer (ignore environment)
219	        const { data: fuzzy } = await supabase
220	            .from('dim_contexts')
221	            .select('context_id, issue_type, environment')
222	            .eq('customer_id', customerId)
223	            .eq('issue_type', normalizedIssueType)
224	            .limit(1)
225	            .maybeSingle();
226	
227	        if (fuzzy?.context_id) {
228	            return {
229	                resolved: true,
230	                contextId: fuzzy.context_id as string,
231	                label: `${normalizedIssueType} / ${fuzzy.environment ?? 'any'} (env fallback)`,
232	            };
233	        }
234	
235	        // Context doesn't exist yet — cold start; signal is globally blended
236	        return { resolved: false, contextId: null, label: `${normalizedIssueType} (cold start)` };
237	    } catch {
238	        return { resolved: false, contextId: null, label: null };
239	    }
