298	function addOutcomeCount(
299	    agentTaskTotals: Map<string, Map<string, number>>,
300	    agentGrandTotals: Map<string, number>,
301	    agentSuccessStats: Map<string, { wins: number; rated: number }>,
302	    agentId: string,
303	    taskName: string,
304	    increment: number,
305	    success: boolean | null,
306	    score: number | null,
307	    scoreRaw: number | null,
308	): void {
309	    if (!agentId || !taskName || !Number.isFinite(increment) || increment <= 0) {
310	        return;
311	    }
312	
313	    let taskMap = agentTaskTotals.get(agentId);
314	    if (!taskMap) {
315	        taskMap = new Map<string, number>();
316	        agentTaskTotals.set(agentId, taskMap);
317	    }
318	
319	    taskMap.set(taskName, (taskMap.get(taskName) ?? 0) + increment);
320	    agentGrandTotals.set(agentId, (agentGrandTotals.get(agentId) ?? 0) + increment);
321	
322	    // Track win rate across all tasks for this agent
323	    const stats = agentSuccessStats.get(agentId) ?? { wins: 0, rated: 0 };
324	    const finalScore = scoreRaw ?? score ?? (success === true ? 1 : success === false ? 0 : null);
325	    if (finalScore !== null) {
326	        stats.rated += increment;
327	        stats.wins += (finalScore * increment);
328	        agentSuccessStats.set(agentId, stats);
329	    }
330	}
