332	async function fetchAgentTaskOutcomeTotals(params: {
333	    customerId: string;
334	    agentId: string | null;
335	}): Promise<{
336	    agentTaskTotals: Map<string, Map<string, number>>;
337	    agentGrandTotals: Map<string, number>;
338	    agentSuccessStats: Map<string, { wins: number; rated: number }>;
339	    source: 'fact_outcomes';
340	}> {
341	    const { customerId, agentId } = params;
342	    const agentTaskTotals = new Map<string, Map<string, number>>();
343	    const agentGrandTotals = new Map<string, number>();
344	    const agentSuccessStats = new Map<string, { wins: number; rated: number }>();
345	
346	    for (let offset = 0; ; offset += SUPABASE_PAGE_SIZE) {
347	        let factsQuery = supabase
348	            .from('fact_outcomes')
349	            .select('agent_id, task_name, success, outcome_score, outcome_score_raw')
350	            .eq('customer_id', customerId)
351	            .eq('is_synthetic', false)
352	            .eq('is_deleted', false)
353	            .neq('agent_id', ZERO_UUID_AGENT_ID)
