355	
356	        if (agentId) {
357	            factsQuery = factsQuery.eq('agent_id', agentId);
358	        }
359	
360	        const { data, error } = await factsQuery;
361	        if (error) {
362	            throw new Error(`[agent-summary] fallback aggregation failed: ${error.message}`);
363	        }
364	
365	        const page = (data ?? []) as Array<{ 
366	            agent_id: string | null; 
367	            task_name: string | null;
368	            success: boolean | null;
369	            outcome_score: number | null;
370	            outcome_score_raw: number | null;
371	        }>;
372	        for (const row of page) {
373	            addOutcomeCount(
374	                agentTaskTotals,
375	                agentGrandTotals,
376	                agentSuccessStats,
377	                row.agent_id ?? '',
378	                row.task_name ?? '',
379	                1,
380	                row.success,
