496	// ── GET /task-analytics ──────────────────────────────────────
497	// Computes three signals the main recommendation response doesn't include:
498	//   1. Drift trendline — sliding-window linear regression on success rate over
499	//      the last N outcomes, giving slope + confidence so the UI can show
500	//      "success rate is silently dropping" before it hits the noise gate.
501	//   2. Explore/exploit ratio — fraction of outcomes that were exploration events
502	//      (cross_event_status != 'none' or is_synthetic) vs exploitation.
503	//   3. Trust blocks — how many outcomes were blocked/logged while trust_status
504	//      was below threshold (recorded via execution_status='FAILED' + failure_reason_code='TRUST_GATE').
505	//
506	// All queries are read-only against fact_outcomes.
507	// Required query params: task (string), agent_id (UUID)
508	// Optional: window (integer, default 50) — outcome count for drift window
509	getRecommendationsRouter.get('/task-analytics', async (c) => {
510	    c.header('Cache-Control', 'no-store');
511	    const customerId = c.get('customer_id') as string | undefined;
512	    if (!customerId) {
513	        return c.json({ error: 'Unauthorized', code: 'MISSING_CUSTOMER_ID' }, 401);
514	    }
515	
516	    const rawTask = c.req.query('task')?.trim() || null;
517	    const rawAgentId = c.req.query('agent_id')?.trim() || null;
518	    const windowSize = Math.max(20, Math.min(200, parseInt(c.req.query('window') ?? '50', 10) || 50));
519	
520	    if (!rawTask) {
521	        return c.json({ error: 'Missing required query parameter: task', code: 'MISSING_TASK' }, 400);
522	    }
523	    if (!rawAgentId) {
524	        return c.json({ error: 'Missing required query parameter: agent_id', code: 'MISSING_AGENT_ID' }, 400);
525	    }
526	
527	    try {
528	        // Run drift-window query and action-aggregate query in parallel.
529	        // The drift query is limited to a recent window; action aggregates are all-time.
530	        // Action aggregates are needed when trust gate blocks the engine (all_actions=[]).
531	        const [driftResult, actionResult] = await Promise.all([
532	            supabase
533	                .from('fact_outcomes')
534	                .select('success, outcome_score, outcome_score_raw, execution_status, failure_reason_code, cross_event_status, is_synthetic, timestamp, data_quality')
535	                .eq('customer_id', customerId)
536	                .eq('agent_id', rawAgentId)
537	                .eq('task_name', rawTask)
538	                .eq('is_deleted', false)
539	                .eq('is_synthetic', false)
540	                .order('timestamp', { ascending: false })
541	                .limit(windowSize * 2),
542	            supabase
543	                .from('fact_outcomes')
544	                .select('action_id, outcome_score, outcome_score_raw, success, execution_status, timestamp, dim_actions(action_name)')
545	                .eq('customer_id', customerId)
546	                .eq('agent_id', rawAgentId)
547	                .eq('task_name', rawTask)
548	                .eq('is_deleted', false)
549	                .eq('is_synthetic', false)
550	                .order('timestamp', { ascending: false })
551	                .limit(5000),
552	        ]);
553	
554	        if (driftResult.error) {
555	            throw new Error(`[task-analytics] drift query failed: ${driftResult.error.message}`);
556	        }
557	
558	        const rows = (driftResult.data ?? []) as Array<{
559	            success: boolean | null;
560	            outcome_score: number | null;
561	            outcome_score_raw: number | null;
562	            execution_status: string | null;
563	            failure_reason_code: string | null;
564	            cross_event_status: string | null;
565	            is_synthetic: boolean | null;
566	            timestamp: string | null;
567	            data_quality: number | null;
568	        }>;
569	
570	        // ── Action aggregates (for trust-blocked fallback) ────
571	        type ActionAgg = { action_id: string; action_name: string; total_count: number; score_sum: number; score_count: number; last_seen_at: string | null };
572	        const actionAggMap = new Map<string, ActionAgg>();
573	        for (const raw of (actionResult.data ?? []) as Array<Record<string, unknown>>) {
574	            const actionId = typeof raw.action_id === 'string' ? raw.action_id : null;
575	            if (!actionId) continue;
576	            const rel = raw.dim_actions;
577	            const actionName: string = (Array.isArray(rel) ? (rel[0] as any)?.action_name : (rel as any)?.action_name) ?? actionId;
578	            const rawScore = typeof raw.outcome_score_raw === 'number' ? raw.outcome_score_raw
579	                : typeof raw.outcome_score === 'number' ? raw.outcome_score : null;
580	            const statusScore = typeof raw.execution_status === 'string'
581	                ? (raw.execution_status.toUpperCase() === 'COMPLETED' ? 1 : raw.execution_status.toUpperCase() === 'FAILED' ? 0 : null)
582	                : null;
583	            const score = rawScore ?? statusScore ?? (raw.success === true ? 1 : raw.success === false ? 0 : null);
584	            const ts = typeof raw.timestamp === 'string' ? raw.timestamp : null;
585	            const key = actionId;
586	            const agg = actionAggMap.get(key) ?? { action_id: actionId, action_name: actionName, total_count: 0, score_sum: 0, score_count: 0, last_seen_at: null };
587	            agg.total_count += 1;
588	            if (score !== null) { agg.score_sum += score; agg.score_count += 1; }
589	            if (ts && (!agg.last_seen_at || ts > agg.last_seen_at)) agg.last_seen_at = ts;
590	            actionAggMap.set(key, agg);
591	        }
592	        const actionAggregates = Array.from(actionAggMap.values())
593	            .map((a) => ({
594	                action_id: a.action_id,
595	                action_name: a.action_name,
596	                total_count: a.total_count,
597	                effective_sample_count: a.total_count,
598	                resolution_rate: a.score_count > 0 ? Number((a.score_sum / a.score_count).toFixed(4)) : 0,
599	                ml_score: null,
600	                semantic_cluster_convergence: null,
601	                last_seen_at: a.last_seen_at,
602	            }))
603	            .sort((a, b) => b.resolution_rate - a.resolution_rate);
604	
605	        if (rows.length === 0 && actionAggregates.length === 0) {
606	            return c.json({
607	                drift: { slope: null, confidence: null, window_size: 0, direction: 'unknown', points: [] },
608	                explore_exploit: { explore_count: 0, exploit_count: 0, total: 0, explore_ratio: null },
609	                trust_blocks: { blocked_count: 0, total: 0 },
610	                action_aggregates: [],
611	            }, 200);
612	        }
613	
614	        // ── 1. Drift trendline ────────────────────────────────
615	        // Reverse to chronological order, take last `windowSize`.
616	        // Use a 5-outcome sliding window to compute local success rate at each step,
617	        // then run linear regression (OLS) on those rates vs. position index.
618	        const chronological = [...rows].reverse().slice(-windowSize);
619	        const SLIDING = 5;
620	        const points: Array<{ index: number; rate: number; timestamp: string }> = [];
621	
622	        for (let i = SLIDING - 1; i < chronological.length; i++) {
623	            const slice = chronological.slice(i - SLIDING + 1, i + 1);
624	            let successSum = 0;
625	            let count = 0;
626	            for (const r of slice) {
627	                const score = typeof r.outcome_score === 'number' ? r.outcome_score
628	                    : typeof r.outcome_score_raw === 'number' ? r.outcome_score_raw
629	                        : typeof r.success === 'boolean' ? (r.success ? 1 : 0)
630	                            : null;
631	                if (score !== null) {
632	                    successSum += score;
633	                    count++;
634	                }
635	            }
636	            if (count > 0) {
637	                points.push({
638	                    index: i,
639	                    rate: Number((successSum / count).toFixed(4)),
640	                    timestamp: chronological[i]!.timestamp ?? '',
641	                });
642	            }
643	        }
644	
645	        let slope: number | null = null;
646	        let rSquared: number | null = null;
647	
648	        if (points.length >= 4) {
649	            const n = points.length;
650	            const xs = points.map((p) => p.index);
651	            const ys = points.map((p) => p.rate);
652	            const xMean = xs.reduce((a, b) => a + b, 0) / n;
653	            const yMean = ys.reduce((a, b) => a + b, 0) / n;
654	            const ssXY = xs.reduce((acc, x, i) => acc + (x - xMean) * (ys[i]! - yMean), 0);
655	            const ssXX = xs.reduce((acc, x) => acc + (x - xMean) ** 2, 0);
656	            const ssYY = ys.reduce((acc, y) => acc + (y - yMean) ** 2, 0);
657	
658	            if (ssXX > 0) {
659	                slope = Number((ssXY / ssXX).toFixed(6));
660	                rSquared = ssYY > 0 ? Number(((ssXY ** 2) / (ssXX * ssYY)).toFixed(4)) : 1;
661	            }
662	        }
663	
664	        const direction: 'improving' | 'stable' | 'degrading' | 'unknown' =
665	            slope === null ? 'unknown'
666	                : slope > 0.002 ? 'improving'
667	                    : slope < -0.002 ? 'degrading'
668	                        : 'stable';
669	
670	        // ── 2. Explore / exploit ──────────────────────────────
671	        // Exploration = cross_event_status is 'pending_signal' or 'conflict' (engine pushed a test action).
672	        // Exploitation = confirmed, resolved, or 'none' (engine used its best known action).
673	        let exploreCount = 0;
674	        let exploitCount = 0;
675	        for (const r of rows) {
676	            const status = r.cross_event_status ?? 'none';
677	            if (status === 'pending_signal' || status === 'conflict') {
678	                exploreCount++;
679	            } else {
680	                exploitCount++;
681	            }
682	        }
683	        const total = rows.length;
684	        const exploreRatio = total > 0 ? Number((exploreCount / total).toFixed(4)) : null;
685	
686	        // ── 3. Trust blocks ───────────────────────────────────
687	        // A trust block is an outcome that was logged with failure_reason_code = 'TRUST_GATE'
688	        // OR execution_status = 'FAILED' while failure_reason_code contains 'TRUST'.
689	        const blockedCount = rows.filter((r) => {
690	            const code = (r.failure_reason_code ?? '').toUpperCase();
691	            return code.includes('TRUST') || code === 'TRUST_GATE';
692	        }).length;
693	
694	        return c.json({
695	            drift: {
696	                slope,
697	                confidence: rSquared,
698	                window_size: chronological.length,
699	                direction,
700	                points: points.slice(-30), // cap response size — last 30 points enough for a sparkline
701	            },
702	            explore_exploit: {
703	                explore_count: exploreCount,
704	                exploit_count: exploitCount,
705	                total,
706	                explore_ratio: exploreRatio,
707	            },
708	            trust_blocks: {
709	                blocked_count: blockedCount,
710	                total,
711	            },
712	            // All-time action aggregates from fact_outcomes — available even when trust gate blocks the engine.
713	            action_aggregates: actionAggregates,
714	        }, 200);
715	    } catch (err: any) {
716	        console.error('[task-analytics] unexpected error:', err.message);
717	        return c.json({ error: 'Internal server error', code: 'INTERNAL_ERROR', details: err.message }, 500);
718	    }
719	});
